import org.owasp.esapi.ESAPI;

public class XssSecureCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encode user input using ESAPI to prevent XSS
        String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);

        // Include the properly encoded user input in the output HTML
        String output = "<div>" + encodedUserInput + "</div>";

        System.out.println(output);
    }
}

